import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import './AICoach.css';

const TABS = [
  { id: 'dashboard', label: 'Neural Dashboard', icon: '⚡' },
  { id: 'directives', label: 'Optimization Protocol', icon: '🎯' },
  { id: 'analytics', label: 'Deep Biometrics', icon: '📊' }
];

const DIRECTIVES = [
  { id: 1, title: 'Dopamine Detox Sequence', description: 'Your sensory input is 42% above baseline. Engage in 15 mins of absolute silence. Avoid all digital interfaces to re-sensitize dopamine receptors.', icon: '🧠', difficulty: 'Hard' },
  { id: 2, title: 'Circadian Realignment', description: 'Melatonin generation is lagging. Dim screen brightness and deploy blue-light blockers right now to initiate optimal sleep induction.', icon: '🌙', difficulty: 'Medium' },
  { id: 3, title: 'Parasympathetic Activation', description: 'Heart Rate Variability (HRV) dropping rapidly. Deploy Box Breathing modality immediately to down-regulate nervous system.', icon: '🫁', difficulty: 'Easy' },
  { id: 4, title: 'Cognitive Offloading', description: 'Working memory capacity maxed out resulting in decreased strategic capability. Perform a brain-dump in your Journal.', icon: '📝', difficulty: 'Medium' }
];

function AICoach({ user }) {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [systemLog, setSystemLog] = useState("");

  useEffect(() => {
    // Futuristic typing effect for the system feed
    const msgs = [
      "Analyzing baseline neuro-metrics...",
      "Calibrating stress predictors...",
      "Optimizing cognitive load vectors...",
      "MindSync Engine online. You are operating at 68% of peak capacity."
    ];
    let i = 0;
    const interval = setInterval(() => {
      setSystemLog(msgs[i]);
      i = i < msgs.length - 1 ? i + 1 : i;
      if(i === msgs.length - 1) clearInterval(interval);
    }, 1500);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="ai-beast-container">

        {/* HEADER */}
        <div className="ai-beast-header">
          <div className="ai-header-content">
            <div className="ai-core-spinner">
              <div className="core-ring r1"></div>
              <div className="core-ring r2"></div>
              <div className="core-center"></div>
            </div>
            <div className="ai-title">
              <h2>MindSync Sentinel X</h2>
              <p>Autonomous Neuro-Optimization AI</p>
            </div>
          </div>
        </div>

        {/* BODY */}
        <div className="ai-beast-body">
          {/* SIDEBAR */}
          <div className="ai-sidebar">
            {TABS.map(t => (
              <button 
                key={t.id} 
                className={`ai-nav-item ${activeTab === t.id ? 'active' : ''}`}
                onClick={() => setActiveTab(t.id)}
              >
                <span>{t.icon}</span> {t.label}
              </button>
            ))}
          </div>

          {/* MAIN CONTENT */}
          <div className="ai-content-area">
            <AnimatePresence mode="wait">
              {activeTab === 'dashboard' && (
                <motion.div 
                   key="dash"
                   initial={{ opacity: 0, x: 20 }}
                   animate={{ opacity: 1, x: 0 }}
                   exit={{ opacity: 0, x: -20 }}
                   transition={{ duration: 0.3 }}
                >
                  <div className="ai-dashboard-grid">
                    {/* Bio-States */}
                    <div className="ai-glass-card">
                      <h3>⚕️ Real-time Cognitive State</h3>

                      <div className="bio-stat">
                        <div className="bio-header"><span>Cortisol / Stress</span> <span className="bio-value" style={{color: '#f43f5e'}}>Elevated</span></div>
                        <div className="bio-bar-bg"><motion.div initial={{width:0}} animate={{width:'75%'}} className="bio-bar-fill" style={{background: '#f43f5e', color: '#f43f5e'}} /></div>
                      </div>

                      <div className="bio-stat">
                        <div className="bio-header"><span>Neuroplasticity</span> <span className="bio-value" style={{color: '#10b981'}}>Optimal</span></div>
                        <div className="bio-bar-bg"><motion.div initial={{width:0}} animate={{width:'90%'}} className="bio-bar-fill" style={{background: '#10b981', color: '#10b981'}} /></div>
                      </div>

                      <div className="bio-stat">
                        <div className="bio-header"><span>Focus Capacity</span> <span className="bio-value" style={{color: '#38bdf8'}}>Depleting</span></div>
                        <div className="bio-bar-bg"><motion.div initial={{width:0}} animate={{width:'40%'}} className="bio-bar-fill" style={{background: '#38bdf8', color: '#38bdf8'}} /></div>
                      </div>
                    </div>

                    {/* Quick Analysis */}
                    <div className="ai-glass-card" style={{ background: 'linear-gradient(135deg, rgba(139, 92, 246, 0.1), rgba(0,0,0,0))', borderColor: 'rgba(139, 92, 246, 0.3)' }}>
                      <h3>👁️ MindSync Analysis</h3>
                      <p style={{ color: '#cbd5e1', lineHeight: 1.6, fontSize: '15px', margin: 0 }}>
                        Your data indicates a heavy cognitive load over the last 4 hours. Pattern recognition reveals a high probability of mental fatigue if intervention is not applied immediately. 
                        <br/><br/>
                        <b>Recommendation:</b> Disconnect from all digital interfaces and initiate the Parasympathetic Activation protocol.
                      </p>
                      <div className="ai-feed-box">
                        <span style={{opacity: 0.7}}>{'>'} </span>
                        <motion.span initial={{opacity:0}} animate={{opacity:1}}>{systemLog}</motion.span>
                        <motion.span animate={{opacity: [0, 1, 0]}} transition={{repeat: Infinity, duration: 0.8}}>_</motion.span>
                      </div>
                    </div>
                  </div>
                </motion.div>
              )}

              {activeTab === 'directives' && (
                <motion.div 
                   key="directives"
                   initial={{ opacity: 0, x: 20 }}
                   animate={{ opacity: 1, x: 0 }}
                   exit={{ opacity: 0, x: -20 }}
                   transition={{ duration: 0.3 }}
                >
                  <h2 style={{ color: 'white', marginTop: 0, marginBottom: '30px', fontSize: '28px', textAlign: 'center' }}>Priority Directives</h2>
                  <div className="directive-list">
                    {DIRECTIVES.map((d, i) => (
                      <motion.div 
                        key={d.id} 
                        className="directive-item"
                        initial={{ opacity: 0, y: 15 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: i * 0.1 }}
                      >
                        <div className="dir-icon">{d.icon}</div>
                        <div className="dir-content" style={{ flex: 1 }}>
                          <h4>{d.title}</h4>
                          <p>{d.description}</p>
                        </div>
                        <div className="dir-actions">
                          <div className="dir-diff">{d.difficulty}</div>
                          <motion.button 
                              whileHover={{ scale: 1.05 }}
                              whileTap={{ scale: 0.95 }}
                              style={{ background: '#38bdf8', border: 'none', padding: '10px 24px', borderRadius: '12px', color: '#0f172a', fontWeight: '800', cursor: 'pointer', boxShadow: '0 4px 15px rgba(56, 189, 248, 0.4)' }}
                          >
                            INITIATE
                          </motion.button>
                        </div>
                      </motion.div>
                    ))}
                  </div>
                </motion.div>
              )}

              {activeTab === 'analytics' && (
                <motion.div 
                   key="analytics"
                   initial={{ opacity: 0, x: 20 }}
                   animate={{ opacity: 1, x: 0 }}
                   exit={{ opacity: 0, x: -20 }}
                   transition={{ duration: 0.3 }}
                   style={{ textAlign: 'center', paddingTop: '80px' }}
                >
                  <div className="ai-core-spinner" style={{ width: '120px', height: '120px', margin: '0 auto 40px' }}>
                    <div className="core-ring r1" style={{ borderTopColor: '#8b5cf6', borderBottomColor: '#8b5cf6' }}></div>
                    <div className="core-ring r2" style={{ borderLeftColor: '#ec4899', borderRightColor: '#ec4899', width: '80%', height: '80%', top: '10%', left: '10%' }}></div>
                    <div className="core-center" style={{ background: '#8b5cf6', boxShadow: '0 0 40px #8b5cf6', width: '20px', height: '20px' }}></div>
                  </div>
                  <h2 style={{ color: 'white', fontSize: '32px', marginBottom: '20px' }}>Deep Biometric Sync Required</h2>
                  <p style={{ color: '#94a3b8', maxWidth: '600px', margin: '0 auto', fontSize: '18px', lineHeight: 1.6 }}>
                    Connect your wearable neuro-tracker or smartwatch to access Level 3 Analytics. MindSync X requires continuous HRV and REM cycle data to unlock this tier.
                  </p>
                  <motion.button 
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                    style={{ background: 'linear-gradient(135deg, #8b5cf6, #ec4899)', border: 'none', padding: '18px 40px', borderRadius: '30px', color: 'white', fontWeight: '800', fontSize: '18px', marginTop: '40px', cursor: 'pointer', boxShadow: '0 10px 30px rgba(139, 92, 246, 0.4)' }}
                  >
                    Connect Device via Bluetooth
                  </motion.button>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>
    </div>
  );
}

export default AICoach;
